INSERT INTO `wp_posts` VALUES (3,1,'2026-06-12 16:24:17','2026-06-12 16:24:17','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we are</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Our website address is: http://localhost:8080.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Comments</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>An anonymized string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service privacy policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Media</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Cookies</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment on our site you may opt-in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Embedded content from other websites</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we share your data with</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you request a password reset, your IP address will be included in the reset email.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">How long we retain your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognize and approve any follow-up comments automatically instead of holding them in a moderation queue.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">What rights you have over your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Where your data is sent</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Visitor comments may be checked through an automated spam detection service.</p>\n<!-- /wp:paragraph -->\n','Privacy Policy','','draft','closed','open','','privacy-policy','','','2026-06-12 16:24:17','2026-06-12 16:24:17','',0,'http://localhost:8080/?page_id=3',0,'page','',0),(4,0,'2026-06-12 23:24:24','2026-06-12 16:24:24','','Trang chủ','','publish','closed','closed','','trang-chu','','','2026-06-12 23:24:24','2026-06-12 16:24:24','',0,'http://localhost:8080/trang-chu/',0,'page','',0),(5,0,'2026-06-12 23:24:24','2026-06-12 16:24:24','','Passion to Profit','','publish','closed','closed','','dich-vu-1','','','2026-06-12 23:24:24','2026-06-12 16:24:24','',0,'http://localhost:8080/dich-vu-1/',0,'page','',0),(6,0,'2026-06-12 23:24:24','2026-06-12 16:24:24','','Business to Freedom','','publish','closed','closed','','dich-vu-2','','','2026-06-12 23:24:24','2026-06-12 16:24:24','',0,'http://localhost:8080/dich-vu-2/',0,'page','',0),(7,0,'2026-06-12 23:24:24','2026-06-12 16:24:24','','Business Mastery','','publish','closed','closed','','dich-vu-3','','','2026-06-12 23:24:24','2026-06-12 16:24:24','',0,'http://localhost:8080/dich-vu-3/',0,'page','',0),(8,0,'2026-06-12 23:24:24','2026-06-12 16:24:24','','Liên hệ','','publish','closed','closed','','lien-he','','','2026-06-12 23:24:24','2026-06-12 16:24:24','',0,'http://localhost:8080/lien-he/',0,'page','',0),(9,0,'2026-06-12 23:24:28','2026-06-12 16:24:28','Trước khi gặp Coach Edina Trâm, tôi đã loay hoay với dự án F&B của mình gần 2 năm mà không có hướng đi rõ ràng. Sau khi được coaching, tôi đã tìm ra định hướng chiến lược rõ ràng và tự tin bước tiếp. Cảm ơn cô đã giúp tôi nhìn thấy tiềm năng của chính mình.','Nguyễn Thị Hảo Hảo','','publish','closed','closed','','nguyen-thi-hao-hao','','','2026-06-12 23:24:28','2026-06-12 16:24:28','',0,'http://localhost:8080/edina_testimonial/nguyen-thi-hao-hao/',0,'edina_testimonial','',0),(10,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Coaching với Edina Trâm là một trong những quyết định đúng đắn nhất tôi từng làm. Chỉ sau 3 buổi, tôi đã có bản kế hoạch hành động cụ thể và lần đầu tiên cảm thấy mình thực sự biết mình đang đi đâu trong hành trình kinh doanh.','Lý Khánh Lê','','publish','closed','closed','','ly-khanh-le','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/ly-khanh-le/',0,'edina_testimonial','',0),(11,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Tôi đã tham gia nhiều khóa học về kinh doanh nhưng Business to Freedom của Coach Edina là khóa thực tế và có chiều sâu nhất. Sau khóa học, doanh thu quán tôi tăng 40% trong 3 tháng tiếp theo. Không chỉ là kiến thức, cô còn truyền cho tôi nguồn năng lượng để tiếp tục tiến lên.','Trần Thị Lý Ly','','publish','closed','closed','','tran-thi-ly-ly','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/tran-thi-ly-ly/',0,'edina_testimonial','',0),(12,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Workshop Passion to Profit đã thay đổi hoàn toàn cách tôi nhìn nhận bản thân và công việc kinh doanh. Tôi tìm ra được \"ikigai\" của mình – giao điểm giữa đam mê, thế mạnh và nhu cầu thị trường. Đây là khoản đầu tư tốt nhất tôi từng bỏ ra.','Vũ Thị Thu Hà','','publish','closed','closed','','vu-thi-thu-ha','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/vu-thi-thu-ha/',0,'edina_testimonial','',0),(13,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Tôi đến workshop với đầy hoài nghi, nhưng ra về với bản Business Model Canvas hoàn chỉnh cho quán bún riêu mà tôi đã mơ ước 5 năm nay. Coach Edina có cách lắng nghe và đặt câu hỏi rất sắc bén, giúp tôi tự tìm ra câu trả lời thay vì chỉ nghe giảng lý thuyết.','Chú Phúc Nga','','publish','closed','closed','','chu-phuc-nga','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/chu-phuc-nga/',0,'edina_testimonial','',0),(14,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Sau 2 ngày workshop, tôi đã có một bản kế hoạch 90 ngày rõ ràng. Tuần đầu tiên về nhà tôi đã thực hiện ngay 3 bước đầu tiên và thấy kết quả ngay. Workshop không chỉ cho tôi kiến thức mà còn cho tôi sự tự tin để bắt đầu.','Nguyễn Hoàng Lâm','','publish','closed','closed','','nguyen-hoang-lam','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/nguyen-hoang-lam/',0,'edina_testimonial','',0),(15,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Là người theo đuổi đam mê nấu ăn từ nhỏ nhưng không biết biến nó thành tiền, workshop Passion to Profit đã cho tôi đúng những gì mình cần. 6 tháng sau workshop, tôi đã ra mắt thương hiệu bánh homemade và có doanh thu ổn định.','Ngô Thị Thùy Nga','','publish','closed','closed','','ngo-thi-thuy-nga','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/ngo-thi-thuy-nga/',0,'edina_testimonial','',0),(16,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Tôi đã từng nghĩ coaching là xa xỉ và không thiết thực. Nhưng buổi workshop của Coach Edina đã thay đổi quan điểm của tôi hoàn toàn. Rất thực tế, rất cụ thể và đầy cảm hứng. Tôi đã giới thiệu cho 4 người bạn tham gia sau đó.','Điềm Trương','','publish','closed','closed','','diem-truong','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/diem-truong/',0,'edina_testimonial','',0),(17,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Business to Freedom đã thay đổi hoàn toàn cách tôi vận hành quán. Trước đây tôi làm 14 tiếng/ngày mà vẫn không đủ. Sau khoá học, tôi xây dựng được SOP rõ ràng, đội nhóm chạy tốt và tôi chỉ cần 6 tiếng/ngày để quản lý. Lợi nhuận tăng 30%.','Caolan Bùi','','publish','closed','closed','','caolan-bui','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/caolan-bui/',0,'edina_testimonial','',0),(18,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Tôi đã từng thất bại với một quán cafe trước đây và mất gần 300 triệu. Nhưng sau khoá Business to Freedom, tôi hiểu mình đã sai ở đâu. Quán thứ 2 của tôi mở ra với bản kế hoạch bài bản hơn và sau 6 tháng đã hòa vốn – nhanh hơn dự kiến 3 tháng.','Phạm Hiếu','','publish','closed','closed','','pham-hieu','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/pham-hieu/',0,'edina_testimonial','',0),(19,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Coach Edina không chỉ dạy kinh doanh mà còn dạy tôi cách làm chủ cuộc sống. Khóa học giúp tôi xây dựng hệ thống để quán có thể chạy mà không cần tôi có mặt hàng ngày. Tôi đã lấy lại được thời gian cho gia đình sau 3 năm bị \"giam cầm\" trong quán.','Thanh Nga Trần','','publish','closed','closed','','thanh-nga-tran','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/thanh-nga-tran/',0,'edina_testimonial','',0),(20,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Sau 10 tuần với Coach Edina, tôi đã có một bộ tài liệu kinh doanh hoàn chỉnh: Business Plan, P&L dự phóng 12 tháng, SOP vận hành và kế hoạch marketing. Đây là nền tảng để tôi tiếp cận nhà đầu tư và mở rộng quy mô.','Lê Quỳnh','','publish','closed','closed','','le-quynh','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/le-quynh/',0,'edina_testimonial','',0),(21,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Coaching 1:1 với Edina Trâm là khoản đầu tư lớn nhất tôi từng bỏ ra cho bản thân, và nó xứng đáng từng đồng. Chỉ sau 4 tháng coaching, tôi đã tái cơ cấu hoàn toàn doanh nghiệp, tăng biên lợi nhuận từ 8% lên 22% và xây dựng được đội ngũ management đáng tin cậy.','Phương Na Bi','','publish','closed','closed','','phuong-na-bi','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/phuong-na-bi/',0,'edina_testimonial','',0),(22,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Điều tôi trân trọng nhất ở Coach Edina là cô ấy không đưa ra giải pháp sẵn có. Cô ấy giúp tôi tự khám phá ra câu trả lời phù hợp với doanh nghiệp của mình. Sau 6 tháng coaching, tôi đã nhượng quyền thành công chi nhánh đầu tiên và đang trong quá trình mở thêm 3 chi nhánh nữa.','Lê Quốc Minh','','publish','closed','closed','','le-quoc-minh','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/le-quoc-minh/',0,'edina_testimonial','',0),(23,0,'2026-06-12 23:24:29','2026-06-12 16:24:29','Tôi tìm đến Business Mastery vì đang ở ngưỡng cửa của một quyết định lớn: mở rộng hay thu hẹp. Coach Edina giúp tôi nhìn rõ bức tranh toàn cảnh và đưa ra quyết định tự tin. Doanh nghiệp của tôi hiện tại đang trong giai đoạn tăng trưởng tốt nhất từ trước đến nay.','Lâu Lan Anh','','publish','closed','closed','','lau-lan-anh','','','2026-06-12 23:24:29','2026-06-12 16:24:29','',0,'http://localhost:8080/edina_testimonial/lau-lan-anh/',0,'edina_testimonial','',0),(24,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Nguyễn Thị Hảo Hảo','','inherit','open','closed','','nguyen-thi-hao-hao-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',9,'http://localhost:8080/wp-content/uploads/2026/06/avatar-01.jpg',0,'attachment','image/jpeg',0),(25,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Lý Khánh Lê','','inherit','open','closed','','ly-khanh-le-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',10,'http://localhost:8080/wp-content/uploads/2026/06/avatar-02.jpg',0,'attachment','image/jpeg',0),(26,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Trần Thị Lý Ly','','inherit','open','closed','','tran-thi-ly-ly-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',11,'http://localhost:8080/wp-content/uploads/2026/06/avatar-03.jpg',0,'attachment','image/jpeg',0),(27,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Vũ Thị Thu Hà','','inherit','open','closed','','vu-thi-thu-ha-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',12,'http://localhost:8080/wp-content/uploads/2026/06/avatar-04.jpg',0,'attachment','image/jpeg',0),(28,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Chú Phúc Nga','','inherit','open','closed','','chu-phuc-nga-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',13,'http://localhost:8080/wp-content/uploads/2026/06/avatar-05.jpg',0,'attachment','image/jpeg',0),(29,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Nguyễn Hoàng Lâm','','inherit','open','closed','','nguyen-hoang-lam-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',14,'http://localhost:8080/wp-content/uploads/2026/06/avatar-06.jpg',0,'attachment','image/jpeg',0),(30,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Ngô Thị Thùy Nga','','inherit','open','closed','','ngo-thi-thuy-nga-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',15,'http://localhost:8080/wp-content/uploads/2026/06/avatar-07.jpg',0,'attachment','image/jpeg',0),(31,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Điềm Trương','','inherit','open','closed','','diem-truong-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',16,'http://localhost:8080/wp-content/uploads/2026/06/avatar-08.jpg',0,'attachment','image/jpeg',0),(32,0,'2026-06-12 23:24:30','2026-06-12 16:24:30','','Caolan Bùi','','inherit','open','closed','','caolan-bui-2','','','2026-06-12 23:24:30','2026-06-12 16:24:30','',17,'http://localhost:8080/wp-content/uploads/2026/06/avatar-09.jpg',0,'attachment','image/jpeg',0),(33,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','','Phạm Hiếu','','inherit','open','closed','','pham-hieu-2','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',18,'http://localhost:8080/wp-content/uploads/2026/06/avatar-10.jpg',0,'attachment','image/jpeg',0),(34,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','','Thanh Nga Trần','','inherit','open','closed','','thanh-nga-tran-2','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',19,'http://localhost:8080/wp-content/uploads/2026/06/avatar-11.jpg',0,'attachment','image/jpeg',0),(35,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','','Lê Quỳnh','','inherit','open','closed','','le-quynh-2','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',20,'http://localhost:8080/wp-content/uploads/2026/06/avatar-12.jpg',0,'attachment','image/jpeg',0),(36,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','','Phương Na Bi','','inherit','open','closed','','phuong-na-bi-2','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',21,'http://localhost:8080/wp-content/uploads/2026/06/avatar-13.jpg',0,'attachment','image/jpeg',0),(37,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','','Lê Quốc Minh','','inherit','open','closed','','le-quoc-minh-2','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',22,'http://localhost:8080/wp-content/uploads/2026/06/avatar-14.jpg',0,'attachment','image/jpeg',0),(38,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','','Lâu Lan Anh','','inherit','open','closed','','lau-lan-anh-2','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',23,'http://localhost:8080/wp-content/uploads/2026/06/avatar-15.jpg',0,'attachment','image/jpeg',0),(39,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','Workshop phù hợp với bất kỳ ai muốn biến đam mê thành kinh doanh: nhân viên văn phòng muốn khởi nghiệp, freelancer muốn scale lên doanh nghiệp, người trẻ chưa biết bắt đầu từ đâu, hay phụ nữ muốn xây dựng nguồn thu nhập độc lập. Không yêu cầu kinh nghiệm kinh doanh trước đó.','Workshop Passion to Profit dành cho ai?','','publish','closed','closed','','workshop-passion-to-profit-danh-cho-ai','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',0,'http://localhost:8080/edina_faq/workshop-passion-to-profit-danh-cho-ai/',0,'edina_faq','',0),(40,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','2 ngày cuối tuần liên tiếp (Thứ 7 và Chủ nhật), từ 9:00 đến 17:00 mỗi ngày. Địa điểm tại Hà Nội hoặc TP.HCM (thông báo cụ thể sau khi đăng ký). Có thể có lựa chọn online cho học viên ở xa.','Workshop diễn ra ở đâu và kéo dài bao lâu?','','publish','closed','closed','','workshop-dien-ra-o-dau-va-keo-dai-bao-lau','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',0,'http://localhost:8080/edina_faq/workshop-dien-ra-o-dau-va-keo-dai-bao-lau/',0,'edina_faq','',0),(41,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','Học phí 499.000 VNĐ. Có chính sách hoàn 100% học phí nếu bạn không hài lòng sau ngày đầu tiên. Ngoài ra có học bổng 50% dành cho sinh viên và người mới tốt nghiệp – liên hệ trực tiếp để biết điều kiện.','Học phí và có hoàn tiền không?','','publish','closed','closed','','hoc-phi-va-co-hoan-tien-khong','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',0,'http://localhost:8080/edina_faq/hoc-phi-va-co-hoan-tien-khong/',0,'edina_faq','',0),(42,0,'2026-06-12 23:24:31','2026-06-12 16:24:31','Bạn sẽ ra về với: (1) Business Model Canvas đầu tiên đã được validate, (2) Kế hoạch hành động 90 ngày chi tiết, (3) Workbook tổng hợp toàn bộ nội dung, (4) Quyền tham gia cộng đồng học viên Edina Trâm, (5) 1 buổi Q&A follow-up sau 30 ngày.','Sau workshop tôi sẽ có được gì?','','publish','closed','closed','','sau-workshop-toi-se-co-duoc-gi','','','2026-06-12 23:24:31','2026-06-12 16:24:31','',0,'http://localhost:8080/edina_faq/sau-workshop-toi-se-co-duoc-gi/',0,'edina_faq','',0),(43,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Hoàn toàn phù hợp! Workshop giúp bạn validate ý tưởng, tìm điểm khác biệt và xây dựng mô hình kinh doanh từ ý tưởng đó. Dù bạn đang ở bước \"có ý tưởng\" hay \"chưa có ý tưởng\", workshop đều có nội dung phù hợp.','Tôi đã có ý tưởng kinh doanh, có phù hợp không?','','publish','closed','closed','','toi-da-co-y-tuong-kinh-doanh-co-phu-hop-khong','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/toi-da-co-y-tuong-kinh-doanh-co-phu-hop-khong/',0,'edina_faq','',0),(44,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Có. Khoá học được thiết kế để giúp cả người đang chuẩn bị mở quán lẫn quán đang gặp khó khăn. Bạn sẽ được phân tích cụ thể nguyên nhân và xây dựng lộ trình khắc phục phù hợp với tình trạng thực tế của mình.','Khoá Business to Freedom có phù hợp với quán đang thua lỗ không?','','publish','closed','closed','','khoa-business-to-freedom-co-phu-hop-voi-quan-dang-thua-lo-khong','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/khoa-business-to-freedom-co-phu-hop-voi-quan-dang-thua-lo-khong/',0,'edina_faq','',0),(45,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','10 buổi online/offline linh hoạt, mỗi buổi 3 tiếng, thường vào tối Thứ 6 hàng tuần từ 19:30 – 22:30. Ngoài ra có các buổi Q&A thêm và nhóm hỗ trợ trên Zalo. Tất cả buổi học đều được ghi lại để xem lại.','Học theo hình thức nào và lịch học như thế nào?','','publish','closed','closed','','hoc-theo-hinh-thuc-nao-va-lich-hoc-nhu-the-nao','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/hoc-theo-hinh-thuc-nao-va-lich-hoc-nhu-the-nao/',0,'edina_faq','',0),(46,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Hoàn toàn được. Khoá học bắt đầu từ nền tảng cơ bản nhất và Coach Edina có cách giải thích tài chính rất dễ hiểu, không cần biết kế toán hay tài chính trước. Mục tiêu là giúp bạn hiểu con số trong chính doanh nghiệp của mình.','Tôi không có nền tảng tài chính, có theo được không?','','publish','closed','closed','','toi-khong-co-nen-tang-tai-chinh-co-theo-duoc-khong','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/toi-khong-co-nen-tang-tai-chinh-co-theo-duoc-khong/',0,'edina_faq','',0),(47,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Tối đa 10 học viên/khoá để đảm bảo Coach Edina có thể coaching sâu sát cho từng bạn. Điều này có nghĩa là suất học rất có hạn và thường được đặt trước 2-4 tuần trước khai giảng.','Lớp có bao nhiêu học viên?','','publish','closed','closed','','lop-co-bao-nhieu-hoc-vien','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/lop-co-bao-nhieu-hoc-vien/',0,'edina_faq','',0),(48,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Có. Sau khoá học bạn được tham gia cộng đồng học viên Business to Freedom – một nhóm chủ quán F&B đang tích cực phát triển. Ngoài ra có các buổi alumni Q&A hàng tháng với Coach Edina để cập nhật và giải quyết các vấn đề mới phát sinh.','Sau khoá học có được hỗ trợ tiếp không?','','publish','closed','closed','','sau-khoa-hoc-co-duoc-ho-tro-tiep-khong','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/sau-khoa-hoc-co-duoc-ho-tro-tiep-khong/',0,'edina_faq','',0),(49,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Business Mastery là chương trình hoàn toàn cá nhân hóa: 100% nội dung xoay quanh doanh nghiệp của bạn, không có template chung hay curriculum cố định. Coach Edina sẽ làm việc trực tiếp trên dữ liệu, thách thức và cơ hội cụ thể của bạn.','Business Mastery coaching 1:1 có gì khác với các khoá học nhóm?','','publish','closed','closed','','business-mastery-coaching-11-co-gi-khac-voi-cac-khoa-hoc-nhom','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/business-mastery-coaching-11-co-gi-khac-voi-cac-khoa-hoc-nhom/',0,'edina_faq','',0),(50,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Gói tiêu chuẩn bao gồm 2 buổi coaching 1:1 mỗi tháng (90 phút/buổi) cộng với hỗ trợ qua tin nhắn không giới hạn trong giờ hành chính. Có thể điều chỉnh tần suất theo nhu cầu và giai đoạn của doanh nghiệp.','Mỗi tháng tôi có bao nhiêu buổi coaching?','','publish','closed','closed','','moi-thang-toi-co-bao-nhieu-buoi-coaching','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/moi-thang-toi-co-bao-nhieu-buoi-coaching/',0,'edina_faq','',0),(51,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Trước buổi đầu tiên, bạn sẽ điền một bảng đánh giá doanh nghiệp chi tiết (Business Diagnostic) để Coach Edina hiểu rõ tình trạng hiện tại. Sau đó chúng ta sẽ có buổi Discovery Session miễn phí 45 phút để xác định mục tiêu coaching và xem đây có phải sự kết hợp phù hợp không.','Tôi cần chuẩn bị gì trước buổi coaching đầu tiên?','','publish','closed','closed','','toi-can-chuan-bi-gi-truoc-buoi-coaching-dau-tien','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/toi-can-chuan-bi-gi-truoc-buoi-coaching-dau-tien/',0,'edina_faq','',0),(52,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Tối thiểu 3 tháng để có thể thấy kết quả rõ ràng và bền vững. Hầu hết khách hàng làm việc với Coach Edina từ 6-12 tháng tùy theo quy mô doanh nghiệp và mục tiêu. Không có hợp đồng dài hạn bắt buộc – bạn có thể tiếp tục hoặc dừng sau mỗi tháng.','Chương trình kéo dài bao lâu?','','publish','closed','closed','','chuong-trinh-keo-dai-bao-lau','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/chuong-trinh-keo-dai-bao-lau/',0,'edina_faq','',0),(53,0,'2026-06-12 23:24:32','2026-06-12 16:24:32','Đây là một trong những lĩnh vực Coach Edina có kinh nghiệm thực tế sâu. Chương trình sẽ giúp bạn chuẩn bị hệ thống, quy trình và tài liệu cần thiết để nhượng quyền thành công, tránh những bẫy phổ biến mà các thương hiệu F&B Việt Nam hay mắc phải.','Coaching có thể giúp gì nếu tôi đang có ý định nhượng quyền?','','publish','closed','closed','','coaching-co-the-giup-gi-neu-toi-dang-co-y-dinh-nhuong-quyen','','','2026-06-12 23:24:32','2026-06-12 16:24:32','',0,'http://localhost:8080/edina_faq/coaching-co-the-giup-gi-neu-toi-dang-co-y-dinh-nhuong-quyen/',0,'edina_faq','',0),(54,0,'2026-06-12 23:24:33','2026-06-12 16:24:33','','Trang chủ','','publish','closed','closed','','trang-chu','','','2026-06-12 23:24:33','2026-06-12 16:24:33','',0,'http://localhost:8080/trang-chu/',1,'nav_menu_item','',0),(55,0,'2026-06-12 23:24:33','2026-06-12 16:24:33','','Passion to Profit','','publish','closed','closed','','passion-to-profit','','','2026-06-12 23:24:33','2026-06-12 16:24:33','',0,'http://localhost:8080/passion-to-profit/',2,'nav_menu_item','',0),(56,0,'2026-06-12 23:24:33','2026-06-12 16:24:33','','Business to Freedom','','publish','closed','closed','','business-to-freedom','','','2026-06-12 23:24:33','2026-06-12 16:24:33','',0,'http://localhost:8080/business-to-freedom/',3,'nav_menu_item','',0),(57,0,'2026-06-12 23:24:33','2026-06-12 16:24:33','','Business Mastery','','publish','closed','closed','','business-mastery','','','2026-06-12 23:24:33','2026-06-12 16:24:33','',0,'http://localhost:8080/business-mastery/',4,'nav_menu_item','',0),(58,0,'2026-06-12 23:24:34','2026-06-12 16:24:34','','Liên hệ','','publish','closed','closed','','lien-he','