INSERT INTO `wp_postmeta` VALUES (2,3,'_wp_page_template','default'),(3,4,'_home_hero_badge','COACHING · MINDFULNESS · TRANSFORMATION'),(4,4,'_home_hero_title','Dẫn lối bình an,<br>khai mở <em>nội lực.</em>'),(5,4,'_home_hero_desc','Đồng hành cùng bạn tìm lại sự rõ ràng trong tâm trí, tự tin trong hành động và sống một cuộc đời đúng với giá trị của chính mình.'),(6,4,'_home_hero_cta1_label','Khám phá dịch vụ'),(7,4,'_home_hero_cta1_url','#services'),(8,4,'_home_hero_cta2_label','Tư vấn 1:1 miễn phí'),(9,4,'_home_hero_cta2_url','/lien-he'),(10,4,'_home_hero_image_alt','Coach Edina Trâm'),(11,4,'_home_hero_value1_title','Chân thực'),(12,4,'_home_hero_value1_desc','Coaching từ trải nghiệm thực tế, không phải lý thuyết'),(13,4,'_home_hero_value2_title','Cá nhân hóa'),(14,4,'_home_hero_value2_desc','Mỗi hành trình đều được thiết kế riêng cho bạn'),(15,4,'_home_hero_value3_title','Chuyển hóa'),(16,4,'_home_hero_value3_desc','Kết quả đo lường được, thay đổi bền vững'),(17,4,'_home_hero_scroll_text','Cuộn xuống'),(18,4,'_home_srv_badge','Hệ sinh thái dịch vụ'),(19,4,'_home_srv_title','Ba chương trình chuyển hóa'),(20,4,'_home_srv_desc','Mỗi chương trình được thiết kế riêng biệt, phục vụ từng giai đoạn trên hành trình phát triển của bạn — từ đam mê cá nhân đến tự do tài chính.'),(21,4,'_home_srv1_num','01'),(22,4,'_home_srv1_title','Passion to Profit'),(23,4,'_home_srv1_subtitle','Workshop 2 ngày'),(24,4,'_home_srv1_desc','Chuyển hóa đam mê thành mô hình kinh doanh có lợi nhuận. Tìm ra lợi thế cạnh tranh, xây dựng nền tảng vững chắc và bắt đầu hành trình khởi nghiệp đầy tự tin.'),(25,4,'_home_srv1_url','/dich-vu-1'),(26,4,'_home_srv1_cta','Tìm hiểu thêm →'),(27,4,'_home_srv2_num','02'),(28,4,'_home_srv2_title','Business to Freedom'),(29,4,'_home_srv2_subtitle','Khoá học 10 tuần'),(30,4,'_home_srv2_desc','Mở rộng quy mô doanh nghiệp, xây dựng hệ thống vận hành tự động và tạo ra cuộc sống tự do mà bạn hằng mơ ước — không cần phải hy sinh sức khỏe hay gia đình.'),(31,4,'_home_srv2_url','/dich-vu-2'),(32,4,'_home_srv2_cta','Tìm hiểu thêm →'),(33,4,'_home_srv3_num','03'),(34,4,'_home_srv3_title','Business Mastery'),(35,4,'_home_srv3_subtitle','Coaching 1:1 chiến lược'),(36,4,'_home_srv3_desc','Chương trình coaching cá nhân hóa dành cho doanh nhân muốn làm chủ mọi khía cạnh — từ chiến lược kinh doanh, lãnh đạo đội ngũ đến phát triển bản thân.'),(37,4,'_home_srv3_url','/dich-vu-3'),(38,4,'_home_srv3_cta','Tìm hiểu thêm →'),(39,4,'_home_about_badge','Người đồng hành'),(40,4,'_home_about_title','Chân thực. Thấu hiểu.<br>Truyền cảm hứng.'),(41,4,'_home_about_name','Edina Trâm'),(42,4,'_home_about_image_alt','Coach Edina Trâm'),(43,4,'_home_about_badge_overlay','ICF PCC Coach'),(44,4,'_home_about_bio','Với hơn 16 năm kinh nghiệm trong ngành F&B và hành trình phát triển bản thân không ngừng, tôi tin rằng mỗi người đều sở hữu một nguồn nội lực phi thường. Sứ mệnh của tôi là đồng hành cùng bạn khơi dậy tiềm năng ấy, để bạn sống một cuộc đời ý nghĩa và trọn vẹn.'),(45,4,'_home_about_cred1','ICF PCC'),(46,4,'_home_about_cred2','16+ Năm Kinh Nghiệm'),(47,4,'_home_about_cred3','F&B Expert'),(48,4,'_home_about_cred4','50+ Doanh Nghiệp'),(49,4,'_home_about_stat1_num','16'),(50,4,'_home_about_stat1_suffix','+'),(51,4,'_home_about_stat1_label','Năm kinh nghiệm'),(52,4,'_home_about_stat2_num','50'),(53,4,'_home_about_stat2_suffix','+'),(54,4,'_home_about_stat2_label','Doanh nghiệp đồng hành'),(55,4,'_home_about_stat3_num','1000'),(56,4,'_home_about_stat3_suffix','+'),(57,4,'_home_about_stat3_label','Cuốn sách đã đọc'),(58,4,'_home_about_stat4_num','3'),(59,4,'_home_about_stat4_suffix',''),(60,4,'_home_about_stat4_label','Chương trình chuyển hóa'),(61,4,'_home_book_badge','Sách mới'),(62,4,'_home_book_title','Ánh Sáng Của Ước Mơ'),(63,4,'_home_book_desc','Cuốn sách chia sẻ hành trình chuyển hóa cá nhân và những bài học quý giá trên con đường kiến tạo cuộc sống ý nghĩa. Một nguồn cảm hứng cho bất kỳ ai đang tìm kiếm sự rõ ràng và mục đích sống.'),(64,4,'_home_